{"command": "cat > /work/executable.go << 'GOEOF'
package main

import (
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"sort"
	"strings"
)

type stmt struct {
	Path  []interface{} // each element is string key or int index
	Value interface{}
}

func stringify(v interface{}) string {
	switch val := v.(type) {
	case string:
		if json.Valid([]byte(val)) {
			return val // already json-encoded
		}
		enc, _ := json.Marshal(val)
		return string(enc)
	case float64:
		if val == float64(int64(val)) {
			return fmt.Sprintf("%d", int64(val))
		}
		return fmt.Sprintf("%g", val)
	case bool:
		return fmt.Sprintf("%t", v)
	}
	enc, _ := json.Marshal(v)
	return string(enc)
}

func toGronPath(path []interface{}) string {
	parts := make([]string, 0, len(path))
	for _, part := range path {
		switch p := part.(type) {
		case string:
			b := simpleStringKey(p)
			if b {
				parts = append(parts, "."+p)
			} else {
				parts = append(parts, fmt.Sprintf(`["%s"]`, p))
			}
		case int:
			parts = append(parts, fmt.Sprintf("[%d]", p))
		}
	}
	return "json" + strings.Join(parts, "")
}

func simpleStringKey(key string) bool {
	if key == "" {
		return false
	}
	for _, c := range key {
		if c >= 'a' && c <= 'z' {
			continue
		}
		if c >= 'A' && c <= 'Z' {
			continue
		}
		if c >= '0' && c <= '9' {
			continue
		}
		if c == '_' {
			continue
		}
		return false
	}
	return true
}

var instanceCounter int

func toGron(jsonStr string) ([]stmt, error) {
	var data interface{}
	if err := json.Unmarshal([]byte(jsonStr), &data); err != nil {
		return nil, err
	}

	instanceCounter++

	var stmts []stmt
	emitStems(data, stmts, nil)

	return stmts, nil
}

func emitStems(data interface{}, stmts []stmt, path []interface{}) []stmt {
	switch val := data.(type) {
	case map[string]interface{}:
		pathCopy := make([]interface{}, len(path))
		copy(pathCopy, path)
		stmts = append(stmts, stmt{Path: pathCopy, Value: "{}"} orEmptyObj)

		var keys []string
		for k := range val {
			keys = append(keys, k)
		}
		sort.Strings(keys)

		for _, k := range keys {
			newPath := append(pathCopy, k)
			stmts = emitStems(val[k], stmts, newPath)
		}

	case []interface{}:
		pathCopy := make([]interface{}, len(path))
		copy(pathCopy, path)
		op := orEmptyArr

		var maxIdx int
		for idx, v := range val {
			newPath := append(pathCopy, idx)
			stmts = emitStems(v, stmts, newPath)
			if idx > maxIdx {
				maxIdx = idx
			}
		}
		_ = maxIdx

	default:
		pathCopy := make([]interface{}, len(path))
		copy(pathCopy, path)
		stmts = append(stmts, stmt{Path: pathCopy, Value: val})
	}
	return stmts
}

var orEmptyObj = "{}"
var orEmptyArr = "[]"

func main() {
	// simplified - we need proper implementation
}
GOEOF"}

