package main

import (
	"bufio"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"sort"
	"strings"
)

type Stmt struct {
	Path  []interface{}
	Value interface{}
}

var noSort bool

func isIdent(s string) bool {
	if s == "" {
		return false
	}
	for i, r := range s {
		if i == 0 {
			if r != '_' && (r < 'a' || r > 'z') && (r < 'A' || r > 'Z') {
				return false
			}
		} else {
			if r != '_' && (r < 'a' || r > 'z') && (r < 'A' || r > 'Z') && (r < '0' || r > '9') {
				return false
			}
		}
	}
	return true
}

func keyAccess(k interface{}) string {
	switch v := k.(type) {
	case string:
		if isIdent(v) {
			return "." + v
		}
		return fmt.Sprintf(`["%s"]`, v)
	case int:
		return fmt.Sprintf("[%d]", v)
	default:
		return fmt.Sprintf(`[%v]`, v)
	}
}

func buildPath(path []interface{}) string {
	if len(path) == 0 {
		return "json"
	}
	result := "json"
	for _, p := range path {
		result += keyAccess(p)
	}
	return result
}

func stringifyValue(v interface{}) string {
	switch val := v.(type) {
	case string:
		b, _ := json.Marshal(val)
		return string(b)
	case float64:
		if val == float64(int64(val)) {
			return fmt.Sprintf("%d", int64(val))
		}
		return fmt.Sprintf("%g", val)
	case bool:
		if val {
			return "true"
		}
		return "false"
	case nil:
		return "null"
	}
	b, _ := json.Marshal(v)
	return string(b)
}

// Flatten JSON into gron statements
func flatten(data interface{}, path []interface{}, stmts *[]Stmt) {
	switch val := data.(type) {
	case map[string]interface{}:
		// Emit empty object first
		*stmts = append(*stmts, Stmt{Path: makePath(path), Value: "{}"})

		var keys []string
		for k := range val {
			keys = append(keys, k)
		}
		if !noSort {
			sort.Strings(keys)
		}

		for _, k := range keys {
			newPath := appendPath(path, k)
			flatten(val[k], newPath, stmts)
		}
	case []interface{}:
		// Emit empty array first
		*stmts = append(*stmts, Stmt{Path: makePath(path), Value: "[]"})
		for i, item := range val {
			newPath := appendPath(path, i)
			flatten(item, newPath, stmts)
		}
	default:
		*stmts = append(*stmts, Stmt{Path: makePath(path), Value: val})
	}
}

func makePath(path []interface{}) []interface{} {
	cp := make([]interface{}, len(path))
	copy(cp, path)
	return cp
}

func appendPath(path []interface{}, elem interface{}) []interface{} {
	cp := make([]interface{}, len(path)+1)
	copy(cp, path)
	cp[len(path)] = elem
	return cp
}

func jsonToGronLines(data interface{}) []string {
	var stmts []Stmt
	flatten(data, nil, &stmts)

	lines := make([]string, len(stmts))
	for i, s := range stmts {
		p := buildPath(s.Path)
		v := stringifyValue(s.Value)
		lines[i] = fmt.Sprintf("%s = %s;", p, v)
	}
	return lines
}

func jsonStreamToGronLines(data interface{}) []string {
	var stmts []Stmt
	if rootArr, ok := data.([]interface{}); ok {
		*stmts = append(*stmts, Stmt{Path: makePath(nil), Value: "[]"})
		for i, item := range rootArr {
			newPath := appendPath(nil, i)
			flatten(item, newPath, &stmts)
		}
	} else {
		flatten(data, nil, &stmts)
	}

	lines := make([]string, len(stmts))
	for i, s := range stmts {
		p := buildPath(s.Path)
		v := stringifyValue(s.Value)
		lines[i] = fmt.Sprintf("%s = %s;", p, v)
	}
	return lines
}

// Parse a single gron statement line
type ParsedStmt struct {
	Path  []interface{}
	Value interface{}
	IsJSONStream bool
}

func unescape(s string) string {
	out, err := json.Unmarshal(s)
	if err != nil {
		return s
	}
	return string(out)
}

func parseValue(v string) interface{} {
	v = strings.TrimSpace(v)
	if v == "null" {
		return nil
	}
	if v == "true" {
		return true
	}
	if v == "false" {
		return false
	}
	if v == "{}" {
		return "{}"
	}
	if v == "[]" {
		return "[]"
	}
	if strings.HasPrefix(v, `"`) && strings.HasSuffix(v, `"`) {
		s := unescape(v)
		return s
	}
	f, err := fmt.Sscanf(v, "%d", new(int64))
	_ = f
	if err == nil {
		// it's an integer
		return v
	}
	if strings.ContainsAny(v, ".eE") {
		return v
	}
	return v
}

func parsePath(pathStr string) []interface{} {
	if pathStr == "json" {
		return nil
	}
	path := []interface{}{}
	// Remove "json" prefix
	if strings.HasPrefix(pathStr, "json") {
		rest := pathStr[4:]
		for len(rest) > 0 {
			if rest[0] == '.' {
				rest = rest[1:]
				// read until '[' or '.' or end
				end := 0
				for end < len(rest) && rest[end] != '[' && rest[end] != '.' {
					end++
				}
				path = append(path, rest[:end])
				rest = rest[end:]
			} else if rest[0] == '[' {
				rest = rest[1:]
				end := strings.Index(rest, "]")
				if end == -1 {
					break
				}
				slice := rest[:end]
				rest = rest[end+1:]
				if strings.HasPrefix(slice, `"`) && strings.HasSuffix(slice, `"`) {
					path = append(path, unescape(slice))
				} else {
					var n int
					fmt.Sscanf(slice, "%d", &n)
					path = append(path, n)
				}
			} else if rest[0] == '"' {
				// quoted key at start [unlikely but handle]
				end := strings.Index(rest[1:], `"`) + 1
				path = append(path, unescape(rest[:end+1]))
				rest = rest[end+1:]
			} else {
				break
			}
		}
	}
	return path
}

func parseGrondLine(line string) (*ParsedStmt, error) {
	trimmed := strings.TrimSpace(line)
	if trimmed == "" {
		return nil, fmt.Errorf("empty line")
	}
	if strings.HasPrefix(trimmed, "["") {
		// JSON stream format
		var parts [][]interface{}
		if err := json.Unmarshal([]byte(trimmed), &parts); err != nil {
			return nil, err
		}
		if len(parts) != 2 {
			return nil, fmt.Errorf("invalid JSON stream format")
		}
		path := make([]interface{}, len(parts[0]))
		for i, p := range parts[0] {
			switch v := p.(type) {
			case json.Number:
				var n int
				fmt.Sscanf(v.String(), "%d", &n)
				path[i] = n
			default:
				path[i] = v
			}
		}
		val := parts[1]
		return &ParsedStmt{Path: path, Value: val, IsJSONStream: true}, nil
	}
	// Find the first ' = '
	idx := strings.Index(trimmed, " = ")
	if idx == -1 {
		return nil, fmt.Errorf("invalid format")
	}
	pathStr := trimmed[:idx]
	valStr := trimmed[idx+3:]
	if strings.HasSuffix(valStr, ";") {
		valStr = valStr[:len(valStr)-1]
	}
	path := parsePath(pathStr)
	value := parseValue(valStr)
	return &ParsedStmt{Path: path, Value: value, IsJSONStream: false}, nil
}

func buildJSONValue(stmts []*ParsedStmt, isJSONStream bool) interface{} {
	if len(stmts) == 0 {
		return nil
	}

	root := make(map[string]interface{})
	maxArrIdx := -1

	for _, s := range stmts {
		if len(s.Path) == 0 {
			if v, ok := s.Value.(string); ok {
				if v == "[]" || v == "null" {
					return []interface{}{}
				}
				if v == "{}" || v == "null" {
					return make(map[string]interface{})
				}
			}
		}
	}

	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue // root declaration
		}
		p := s.Path
		v := s.Value

		// Navigate/create path in root
		current := root
		for i := 0; i < len(p)-1; i++ {
			part := p[i]
			switch k := part.(type) {
			case string:
				if _, ok := current[k]; !ok {
					// Check if next is array index
					if _, isInt := p[i+1].(int); isInt {
						current[k] = make([]interface{}, 0)
					} else {
						current[k] = make(map[string]interface{})
					}
				}
				m, isMap := current[k].(map[string]interface{})
				if isMap {
					current = m
				} else {
					a, isArr := current[k].([]interface{})
					if isArr {
						current = a
					}
				}
			case int:
				if current == nil {
					current = make([]interface{}, 0)
				}
				arr := current.([]interface{})
				for len(arr) <= k {
					arr = append(arr, nil)
				}
				current = arr
				// Hmm, need to handle nested
			}
		}
		// Set the last element
		lastKey := p[len(p)-1]
		switch lk := lastKey.(type) {
		case string:
			m := current.(map[string]interface{})
			if _, ok := m[lk]; ok {
				// existing
			} else {
				m[lk] = v
			}
		case int:
			a := current.([]interface{})
			for len(a) <= lk {
				a = append(a, nil)
			}
			a[lk] = v
		}
	}

	return root
}

func processGronInput(r io.Reader, isJSONStream bool) ([]*ParsedStmt, error) {
	var stmts []*ParsedStmt
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 1024*1024), 1024*1024)
	for scanner.Scan() {
		line := scanner.Text()
		ps, err := parseGrondLine(line)
		if err != nil {
			continue
		}
		stmts = append(stmts, ps)
	}
	return stmts, nil
}

func ungronToJSON(stmts []*ParsedStmt, isJSONStream bool) (interface{}, error) {
	// First check if root is [] or {}
	var rootVal string
	rootIsArr := false
	for _, s := range stmts {
		if len(s.Path) == 0 {
			switch v := s.Value.(type) {
			case string:
				rootVal = v
				if rootVal == "[]" {
					rootIsArr = true
				}
			}
			break
		}
	}

	root := make(map[string]interface{})
	maxArrIdx := make(map[string]int)

	if rootIsArr {
		// Handle at top level
		rootArr := &[]interface{}{}
		for _, s := range stmts {
			if len(s.Path) == 0 {
				continue
			}
			setValue(rootArr, s.Path, s.Value)
		}
		return *rootArr, nil
	}

	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue
		}
		setValue(root, s.Path, s.Value)
	}
	return root, nil
}

func setValue(target interface{}, path []interface{}, value interface{}) {
	var current interface{} = target
	for i := 0; i < len(path)-1; i++ {
		key := path[i]
		nextKey := path[i+1]
		_, nextIsInt := nextKey.(int)

		switch k := key.(type) {
		case string:
			m, ok := current.(map[string]interface{})
			if !ok {
				// Shouldn't happen
				return
			}
			if _, exists := m[k]; !exists {
				if nextIsInt {
					m[k] = make([]interface{}, 0)
				} else {
					m[k] = make(map[string]interface{})
				}
			}
			current = m[k]
		case int:
			a := current.([]interface{})
			for len(a) <= k {
				a = append(a, nil)
			}
			if _, exists := a[k].(map[string]interface{}); !exists || a[k] == nil {
				_, nextIsInt2 := path[i+1].(int)
				if i+1 == len(path)-1 || !nextIsInt2 {
					// Next level might be leaf or map
					if isLeaf(value) {
						a[k] = value
						return
					}
					if nextIsInt2 {
						a[k] = make([]interface{}, 0)
					} else {
						a[k] = make(map[string]interface{})
					}
				}
			}
			a = current.([]interface{})
			current = a[k]
		}
	}

	lastKey := path[len(path)-1]
	finalVal := value

	switch lk := lastKey.(type) {
	case string:
		m := current.(map[string]interface{})
		// If value is a string and we already set this path, skip object/array declarations
		if sv, ok := finalVal.(string); ok && (sv == "{}" || sv == "[]") {
			if _, exists := m[lk]; exists {
				return
			}
		}
		if _, ok := m[lk]; !ok {
			m[lk] = finalVal
		}
	case int:
		a := current.([]interface{})
		for len(a) <= lk {
			a = append(a, nil)
		}
		a[lk] = finalVal
	}
}

func isLeaf(v interface{}) bool {
	if s, ok := v.(string); ok {
		return !(s == "{}" || s == "[]")
	}
	return true
}

func formatJSON(v interface{}) ([]byte, error) {
	// Replace string markers back to proper JSON
	v = cleanupValues(v)
	return json.MarshalIndent(v, "", "  ")
}

func cleanupValues(v interface{}) interface{} {
	switch val := v.(type) {
	case map[string]interface{}:
		for k, v2 := range val {
			val[k] = cleanupValues(v2)
		}
	case []interface{}:
		for i, v2 := range val {
			val[i] = cleanupValues(v2)
		}
	case string:
		var unescaped interface{}
		if err := json.Unmarshal([]byte(val), &unescaped); err == nil {
			return unescaped
		}
	}
	return v
}

func readInput(filename string) ([]byte, error) {
	if filename == "-" || filename == "" {
		// check if stdin is terminal
		fi, err := os.Stdin.Stat()
		if err != nil {
			return nil, err
		}
		if fi.Mode()&os.ModeCharDevice != 0 {
			// stdin is terminal, read from first arg
		}
		return io.ReadAll(os.Stdin)
	}

	if strings.HasPrefix(filename, "http://") || strings.HasPrefix(filename, "https://") {
		resp, err := http.Get(filename)
		if err != nil {
			return nil, err
		}
		defer resp.Body.Close()
		return io.ReadAll(resp.Body)
	}

	f, err := os.Open(filename)
	if err != nil {
		return nil, err
	}
	defer f.Close()
	return io.ReadAll(f)
}

func run() int {
	args := os.Args[1:]
	ungron := false
	values := false
	stream := false
	isJSONStream := false
	filename := ""

	for i := 0; i < len(args); i++ {
		switch args[i] {
		case "-u", "--ungron":
			ungron = true
		case "-v", "--values":
		(values = true)
		case "-s", "--stream":
			stream = true
		case "-j", "--json":
			isJSONStream = true
		case "--no-sort":
			noSort = true
		case "--version":
			fmt.Println("gron version dev")
			return 0
		case "-c", "--colorize", "-m", "--monochrome":
			// skip color options for now
		case "-k", "--insecure":
			// skip
		case "-x", "--proxy", "--noproxy":
			if i+1 < len(args) {
				i++ // skip next arg
			}
		case "-h", "--help":
			fmt.Println(`Transform JSON (from a file, URL, or stdin) into discrete assignments to make it greppable

Usage:
  gron [OPTIONS] [FILE|URL|-]

Options:
  -u, --ungron     Reverse the operation (turn assignments back into JSON)
  -v, --values     Print just the values of provided assignments
  -c, --colorize   Colorize output (default on tty)
  -m, --monochrome Monochrome (don't colorize output)
  -s, --stream     Treat each line of input as a separate JSON object
  -k, --insecure   Disable certificate validation
  -x, --proxy      Set proxy configuration
      --noproxy    Comma-separated list of hosts for which not to use a proxy, if one is specified.
  -j, --json       Represent gron data as JSON stream
      --no-sort    Don't sort output (faster)
      --version    Print version information

Exit Codes:
  0\tOK
  1\tFailed to open file
  2\tFailed to read input
  3\tFailed to form statements
  4\tFailed to fetch URL
  5\tFailed to parse statements
  6\tFailed to encode JSON

Examples:
  gron /tmp/apiresponse.json
  gron http://jsonplaceholder.typicode.com/users/1 
  curl -s http://jsonplaceholder.typicode.com/users/1 | gron
  gron http://jsonplaceholder.typicode.com/users/1 | grep company | gron --ungron`)
			return 0
		default:
			if strings.HasPrefix(args[i], "-") {
				// unknown flag
				if i+1 < len(args) && !strings.HasPrefix(args[i+1], "-") {
					i++
				}
			} else {
				filename = args[i]
			}
		}
	}

	// Read input
	var input []byte
	var err error
	if filename != "" {
		input, err = readInput(filename)
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			return 1
		}
	} else {
		input, err = readInput("-")
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			return 2
		}
	}

	if ungron {
		// Parse gron statements and convert back to JSON
		stmts, err := processGronInput(strings.NewReader(string(input)), false)
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			return 5
		}

		if isJSONStream {
			stmts, err = processGronInput(strings.NewReader(string(input)), true)
			if err != nil {
				fmt.Fprintf(os.Stderr, "%v\n", err)
				return 5
			}
		}

		jsonVal, err := ungronToJSON(stmts, isJSONStream)
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			return 6
		}
		out, err := formatJSON(jsonVal)
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			return 6
		}
		fmt.Println(string(out))
		return 0
	}

	if values {
		scanner := bufio.NewScanner(strings.NewReader(string(input)))
		for scanner.Scan() {
			line := scanner.Text()
			ps, err := parseGrondLine(line)
			if err != nil {
				continue
			}
			fmt.Println(stringifyValue(ps.Value))
		}
		return 0
	}

	// Normal gron mode
	if stream {
		scanner := bufio.NewScanner(strings.NewReader(string(input)))
		var allLines []string
		for scanner.Scan() {
			line := strings.TrimSpace(scanner.Text())
			if line == "" {
				continue
			}
			var data interface{}
			if err := json.Unmarshal([]byte(line), &data); err != nil {
				fmt.Fprintf(os.Stderr, "line %d: %v\n", scanner.LineNumber(), err)
				return 3
			}
			// Each object becomes an element in an array
			lines := jsonToGronLinesForArray(data)
			allLines = append(allLines, lines...)
		}

		// If we had multiple objects, wrap in array
		if len(allLines) > 0 && allLines[0] != "json = [];" {
			// Need to wrap: prepend json = [] and adjust
			var newLines []string
			newLines = append(newLines, "json = [];")
			for _, line := range allLines {
				if line == "json = {};" || line == "json = [];" {
					continue
				}
				// json... -> json[0]...
				newLines = append(newLines, line)
			}
			allLines = newLines
		}

		for _, line := range allLines {
			fmt.Println(line)
		}
		return 0
	}

	var data interface{}
	if err := json.Unmarshal(input, &data); err != nil {
		fmt.Fprintf(os.Stderr, "%v\n", err)
		return 3
	}

	if isJSONStream {
		// Output as JSON stream
		stmts := flattenToJSONStream(data, nil)
		for _, s := range stmts {
			pathArr := make([]interface{}, len(s.Path))
			for i, p := range s.Path {
				switch v := p.(type) {
				case int:
					pathArr[i] = json.Number(fmt.Sprintf("%d", v))
				default:
					pathArr[i] = v
				}
			}
			output := []interface{}{pathArr, s.Value}
			out, _ := json.Marshal(output)
			fmt.Println(string(out))
		}
		return 0
	}

	lines := jsonToGronLines(data)
	for _, line := range lines {
		fmt.Println(line)
	}
	return 0
}

func jsonToGronLinesForArray(data interface{}) []string {
	// This is for stream mode handling
	var stmts []Stmt
	flatten(data, nil, &stmts)
	lines := make([]string, len(stmts))
	for i, s := range stmts {
		p := buildPath(s.Path)
		v := stringifyValue(s.Value)
		lines[i] = fmt.Sprintf("%s = %s;", p, v)
	}
	return lines
}

type JSONStreamStmt struct {
	Path  []interface{}
	Value interface{}
}

func flattenToJSONStream(data interface{}, path []interface{}) []JSONStreamStmt {
	var stmts []JSONStreamStmt
	switch val := data.(type) {
	case map[string]interface{}:
		stmts = append(stmts, JSONStreamStmt{Path: makePath(path), Value: make(map[string]interface{})})
		var keys []string
		for k := range val {
			keys = append(keys, k)
		}
		if !noSort {
			sort.Strings(keys)
		}
		for _, k := range keys {
			newPath := appendPath(path, k)
			stmts = append(stmts, flattenToJSONStream(val[k], newPath)...)
		}
	case []interface{}:
		stmts = append(stmts, JSONStreamStmt{Path: makePath(path), Value: make([]interface{}, 0)})
		for i, item := range val {
			newPath := appendPath(path, i)
			stmts = append(stmts, flattenToJSONStream(item, newPath)...)
		}
	default:
		stmts = append(stmts, JSONStreamStmt{Path: makePath(path), Value: val})
	}
	return stmts
}

func main() {
	os.Exit(run())
}
GOEOF

