			return 0
		default:
			if strings.HasPrefix(args[i], "-") {
				// unknown flag
				if i+1 < len(args) && !strings.HasPrefix(args[i+1], "-") {
					i++
				}
			} else {
				filename = args[i]
			}
		}
	}

	// Read input
	var input []byte
	var err error
	if filename != "" {
		input, err = readInput(filename)
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			return 1
		}
	} else {
		input, err = readInput("-")
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			return 2
		}
	}

	if ungron {
		// Parse gron statements and convert back to JSON
		stmts, err := processGronInput(strings.NewReader(string(input)), false)
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			return 5
		}

		if isJSONStream {
			stmts, err = processGronInput(strings.NewReader(string(input)), true)
			if err != nil {
				fmt.Fprintf(os.Stderr, "%v\n", err)
				return 5
			}
		}

		jsonVal, err := ungronToJSON(stmts, isJSONStream)
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			return 6
		}
		out, err := formatJSON(jsonVal)
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			return 6
		}
		fmt.Println(string(out))
		return 0
	}

	if values {
		scanner := bufio.NewScanner(strings.NewReader(string(input)))
		for scanner.Scan() {
			line := scanner.Text()
			ps, err := parseGrondLine(line)
			if err != nil {
				continue
			}
			fmt.Println(stringifyValue(ps.Value))
		}
		return 0
	}

	// Normal gron mode
	if stream {
		scanner := bufio.NewScanner(strings.NewReader(string(input)))
		var allLines []string
		for scanner.Scan() {
			line := strings.TrimSpace(scanner.Text())
			if line == "" {
				continue
			}
			var data interface{}
			if err := json.Unmarshal([]byte(line), &data); err != nil {
				fmt.Fprintf(os.Stderr, "line %d: %v\n", scanner.LineNumber(), err)
				return 3
			}
			// Each object becomes an element in an array
			lines := jsonToGronLinesForArray(data)
			allLines = append(allLines, lines...)
		}

		// If we had multiple objects, wrap in array
		if len(allLines) > 0 && allLines[0] != "json = [];" {
			// Need to wrap: prepend json = [] and adjust
			var newLines []string
			newLines = append(newLines, "json = [];")
			for _, line := range allLines {
				if line == "json = {};" || line == "json = [];" {
					continue
				}
				// json... -> json[0]...
				newLines = append(newLines, line)
			}
			allLines = newLines
		}

		for _, line := range allLines {
			fmt.Println(line)
		}
		return 0
	}

	var data interface{}
	if err := json.Unmarshal(input, &data); err != nil {
		fmt.Fprintf(os.Stderr, "%v\n", err)
		return 3
	}

	if isJSONStream {
		// Output as JSON stream
		stmts := flattenToJSONStream(data, nil)
		for _, s := range stmts {
			pathArr := make([]interface{}, len(s.Path))
			for i, p := range s.Path {
				switch v := p.(type) {
				case int:
					pathArr[i] = json.Number(fmt.Sprintf("%d", v))
				default:
					pathArr[i] = v
				}
			}
			output := []interface{}{pathArr, s.Value}
			out, _ := json.Marshal(output)
			fmt.Println(string(out))
		}
		return 0
	}

	lines := jsonToGronLines(data)
	for _, line := range lines {
		fmt.Println(line)
	}
	return 0
}

func jsonToGronLinesForArray(data interface{}) []string {
	// This is for stream mode handling
	var stmts []Stmt
	flatten(data, nil, &stmts)
	lines := make([]string, len(stmts))
	for i, s := range stmts {
		p := buildPath(s.Path)
		v := stringifyValue(s.Value)
		lines[i] = fmt.Sprintf("%s = %s;", p, v)
	}
	return lines
}

type JSONStreamStmt struct {
	Path  []interface{}
	Value interface{}
}

func flattenToJSONStream(data interface{}, path []interface{}) []JSONStreamStmt {
	var stmts []JSONStreamStmt
	switch val := data.(type) {
	case map[string]interface{}:
		stmts = append(stmts, JSONStreamStmt{Path: makePath(path), Value: make(map[string]interface{})})
		var keys []string
		for k := range val {
			keys = append(keys, k)
		}
		if !noSort {
			sort.Strings(keys)
		}
		for _, k := range keys {
			newPath := appendPath(path, k)
			stmts = append(stmts, flattenToJSONStream(val[k], newPath)...)
		}
	case []interface{}:
		stmts = append(stmts, JSONStreamStmt{Path: makePath(path), Value: make([]interface{}, 0)})
		for i, item := range val {
			newPath := appendPath(path, i)
			stmts = append(stmts, flattenToJSONStream(item, newPath)...)
		}
	default:
		stmts = append(stmts, JSONStreamStmt{Path: makePath(path), Value: val})
	}
	return stmts
}

func main() {
	os.Exit(run())
}
