func cleanValues(v interface{}) interface{} {
	switch val := v.(type) {
	case map[string]interface{}:
		for k, v2 := range val {
			val[k] = cleanValues(v2)
		}
	case []interface{}:
		for i, v2 := range val {
			val[i] = cleanValues(v2)
		}
	case rawMarker:
		if val == emptyObj {
			return map[string]interface{}{}
		}
		if val == emptyArr {
			return []interface{}{}
		}
	}
	return v
}

