	v = strings.TrimSpace(v)
	switch v {
	case "null":
		return nil
	case "true":
		return true
	case "false":
		return false
	case "{}":
		return emptyObj
	case "[]":
		return emptyArr
	}
	if len(v) >= 2 && v[0] == '"' && v[len(v)-1] == '"' {
		return unescape(v)
	}
	return v
}

func parsePath(pathStr string) []interface{} {
	if pathStr == "json" {
		return nil
	}
	path := []interface{}{}
	rest := pathStr[4:]
	for len(rest) > 0 {
		if rest[0] == '.' {
			rest = rest[1:]
			end := 0
			for end < len(rest) && rest[end] != '[' && rest[end] != '.' {
				end++
			}
			path = append(path, rest[:end])
			rest = rest[end:]
		} else if rest[0] == '[' {
			rest = rest[1:]
			end := strings.Index(rest, "]")
			if end == -1 {
				break
			}
			slice := rest[:end]
			rest = rest[end+1:]
			if len(slice) >= 2 && slice[0] == '"' && slice[len(slice)-1] == '"' {
				path = append(path, unescape(slice))
			} else {
				var n int
				fmt.Sscanf(slice, "%d", &n)
				path = append(path, n)
			}
		} else {
			break
		}
	}
	return path
}

func parseGrondLine(line string) (*parsedStmt, error) {
	trimmed := strings.TrimSpace(line)
	if trimmed == "" {
		return nil, fmt.Errorf("empty line")
	}
	idx := strings.Index(trimmed, " = ")
	if idx == -1 {
		return nil, fmt.Errorf("invalid format")
	}
	pathStr := trimmed[:idx]
	valStr := trimmed[idx+3:]
	if strings.HasSuffix(valStr, ";") {
		valStr = valStr[:len(valStr)-1]
	}
	path := parsePath(pathStr)
	value := parseValue(valStr)
	return &parsedStmt{Path: path, Value: value}, nil
}

func readStatements(r io.Reader) ([]*parsedStmt, error) {
	var stmts []*parsedStmt
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 1024*1024), 1024*1024)
	for scanner.Scan() {
		line := scanner.Text()
		ps, err := parseGrondLine(line)
		if err != nil {
			continue
		}
		stmts = append(stmts, ps)
	}
	return stmts, nil
}

func isLeafMarker(v interface{}) bool {
	rm, ok := v.(rawMarker)
	return ok && (rm == emptyObj || rm == emptyArr)
}

// expandMap ensures the map has the key set to the right type
func expandMap(m map[string]interface{}, key string, nextIsInt bool) {
	if _, exists := m[key]; exists {
		switch m[key].(type) {
		case map[string]interface{}:
		case []interface{}:
		default:
			if nextIsInt {
				m[key] = make([]interface{}, 0)
			} else {
				m[key] = make(map[string]interface{})
			}
		}
	} else {
		if nextIsInt {
			m[key] = make([]interface{}, 0)
		} else {
			m[key] = make(map[string]interface{})
		}
	}
}

// expandArr ensures the array has index set to the right type
func expandArr(a *[]interface{}, idx int, nextIsInt bool) {
	arr := *a
	for len(arr) <= idx {
		arr = append(arr, nil)
	}
	*a = arr
	if arr[idx] == nil {
		if nextIsInt {
			arr[idx] = make([]interface{}, 0)
		} else {
			arr[idx] = make(map[string]interface{})
		}
	} else {
		switch arr[idx].(type) {
		case map[string]interface{}:
		case []interface{}:
		default:
			if nextIsInt {
				arr[idx] = make([]interface{}, 0)
			} else {
				arr[idx] = make(map[string]interface{})
			}
		}
	}
}

func ungronToJSON(stmts []*parsedStmt) (interface{}, error) {
	if len(stmts) == 0 {
		return nil, nil
	}

	rootIsArr := false
	for _, s := range stmts {
		if len(s.Path) == 0 {
			if rm, ok := s.Value.(rawMarker); ok && rm == emptyArr {
				rootIsArr = true
			}
			break
		}
	}

	if rootIsArr {
		return processRootArray(stmts)
	}
	return processRootObject(stmts)
}

func processRootObject(stmts []*parsedStmt) (interface{}, error) {
	root := make(map[string]interface{})
	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue
		}
		processValue(root, s.Path, s.Value)
	}
	return root, nil
}

func processRootArray(stmts []*parsedStmt) (interface{}, error) {
	root := make([]interface{}, 0)
	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue
		}
		arrPtr := &root
		for i := 0; i < len(s.Path)-1; i++ {
			key := s.Path[i]
			switch k := key.(type) {
			case string:
				m := (*arrPtr).([]interface{})
				// get the right element
				// Hmm, this is getting complex. Let me use a generic function.
				_ = m
			case int:
				a := *arrPtr
				expandArr(&a, k, i+1 < len(s.Path)-1)
				*arrPtr = a
				arrPtr = &a[k]
			}
		}
		_ = arrPtr
	}

	// Simple approach: just find max index and build array
	maxIdx := -1
	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue
		}
		idx := s.Path[0].(int)
		if idx > maxIdx {
			maxIdx = idx
		}
	}
	result := make([]interface{}, maxIdx+1)
	for i := range result {
		result[i] = nil
	}

	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue
		}
		idx := s.Path[0].(int)
		rest := s.Path[1:]
		if rest == nil {
			result[idx] = s.Value
			continue
		}
		if result[idx] == nil {
			// Determine type
			if _, isInt := rest[0].(int); isInt {
				result[idx] = make([]interface{}, 0)
			} else {
				result[idx] = make(map[string]interface{})
			}
		}
		processValue(result[idx], rest, s.Value)
	}
	return result, nil
}

func processValue(container interface{}, path []interface{}, value interface{}) {
	if len(path) == 0 {
		return
	}

	// Ensure all intermediate containers exist
	for i := 0; i < len(path)-1; i++ {
		key := path[i]
		nextIsInt := i+1 < len(path) && func() bool {
			_, ok := path[i+1].(int)
			return ok
		}()

		switch k := key.(type) {
		case string:
			m := container.(map[string]interface{})
			expandMap(m, k, nextIsInt)
			container = m[k]
		case int:
			a := container.([]interface{})
			for len(a) <= k {
				a = append(a, nil)
			}
			if a[k] == nil {
				if nextIsInt {
					a[k] = make([]interface{}, 0)
				} else {
					a[k] = make(map[string]interface{})
				}
			} else {
				switch a[k].(type) {
				case map[string]interface{}:
				case []interface{}:
				default:
					if nextIsInt {
						a[k] = make([]interface{}, 0)
					} else {
						a[k] = make(map[string]interface{})
					}
				}
			}
			container = a[k]
		}
	}

	// Set final value
	lastKey := path[len(path)-1]
	switch lk := lastKey.(type) {
	case string:
		m := container.(map[string]interface{})
		if _, exists := m[lk]; !exists {
			m[lk] = value
		} else if !isLeafMarker(value) {
			m[lk] = value
		}
	case int:
		a := container.([]interface{})
		for len(a) <= lk {
			a = append(a, nil)
		}
		if a[lk] == nil || !isLeafMarker(value) {
			a[lk] = value
		}
	}
}

type jsonStreamEntry struct {
	Path  []interface{}
	Value interface{}
}

func flattenToStream(data interface{}, path []interface{}) []jsonStreamEntry {
	var entries []jsonStreamEntry
	switch val := data.(type) {
	case map[string]interface{}:
		entries = append(entries, jsonStreamEntry{Path: makePathSlice(path), Value: map[string]interface{}{}})
		var keys []string
		for k := range val {
			keys = append(keys, k)
		}
		sort.Slice(keys, func(i, j int) bool {
			ai, aj := isIdent(keys[i]), isIdent(keys[j])
			if ai && !aj {
				return true
			}
			if !ai && aj {
				return false
			}
			if ai && aj {
				li := strings.ToLower(keys[i])
				lj := strings.ToLower(keys[j])
				if li != lj {
					return li < lj
				}
				return keys[i] < keys[j]
			}
			return keys[i] < keys[j]
		})
		for _, k := range keys {
			newPath := appendPath(path, k)
			entries = append(entries, flattenToStream(val[k], newPath)...)
		}
	case []interface{}:
		entries = append(entries, jsonStreamEntry{Path: makePathSlice(path), Value: []interface{}{}})
		for i, item := range val {
			newPath := appendPath(path, i)
			entries = append(entries, flattenToStream(item, newPath)...)
		}
	default:
		entries = append(entries, jsonStreamEntry{Path: makePathSlice(path), Value: val})
	}
	return entries
}

func formatJSON(v interface{}) ([]byte, error) {
	return json.MarshalIndent(cleanValues(v), "", "  ")
}

func cleanValues(v interface{}) interface{} {
	switch val := v.(type) {
	case map[string]interface{}:
		for k, v2 := range val {
			val[k] = cleanValues(v2)
		}
	case []interface{}:
		for i, v2 := range val {
			val[i] = cleanValues(v2)
		}
	case rawMarker:
		if val == emptyObj {
			return map[string]interface{}{}
		}
		if val == emptyArr {
			return []interface{}{}
		}
	}
	return v
}

func readInput(filename string) ([]byte, error) {
	if filename == "-" || filename == "" {
		return io.ReadAll(os.Stdin)
	}
	if strings.HasPrefix(filename, "http://") || strings.HasPrefix(filename, "https://") {
		return nil, fmt.Errorf("URL fetching not supported")
	}
	f, err := os.Open(filename)
	if err != nil {
		return nil, err
	}
	defer f.Close()
	return io.ReadAll(f)
}

func main() {
	args := os.Args[1:]
	ungron := false
	values := false
	stream := false
	jsonStream := false
	filename := ""

	for i := 0; i < len(args); i++ {
		switch args[i] {
		case "-u", "--ungron":
			ungron = true
		case "-v", "--values":
			values = true
		case "-s", "--stream":
			stream = true
		case "-j", "--json":
			jsonStream = true
		case "--no-sort":
		case "--version":
			fmt.Println("gron version dev")
			return
		case "-c", "--colorize", "-m", "--monochrome":
		case "-k", "--insecure":
		case "-x", "--proxy":
			if i+1 < len(args) {
				i++
			}
		case "--noproxy":
			if i+1 < len(args) {
				i++
			}
		case "-h", "--help":
			printHelp()
			return
		default:
			if !strings.HasPrefix(args[i], "-") {
				filename = args[i]
			} else {
				if i+1 < len(args) && !strings.HasPrefix(args[i+1], "-") {
					i++
				}
			}
		}
	}

	var input []byte
	var err error
	if filename != "" {
		input, err = readInput(filename)
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			os.Exit(1)
		}
	} else {
		input, err = readInput("-")
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			os.Exit(2)
		}
	}

	if ungron {
		stmts, _ := readStatements(strings.NewReader(string(input)))

		result, err := ungronToJSON(stmts)
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			os.Exit(6)
		}

		out, err := formatJSON(result)
		if err != nil {
			fmt.Fprintf(os.Stderr, "%v\n", err)
			os.Exit(6)
		}
		fmt.Println(string(out))
		return
	}

	if values {
		stmts, _ := readStatements(strings.NewReader(string(input)))
		for _, s := range stmts {
			fmt.Println(stringifyValue(s.Value))
		}
		return
	}

	if stream {
		lines := strings.Split(string(input), "\n")
		var objects []interface{}
		for _, line := range lines {
			line = strings.TrimSpace(line)
			if line == "" {
				continue
			}
			var data interface{}
			if err := json.Unmarshal([]byte(line), &data); err != nil {
				fmt.Fprintf(os.Stderr, "%v\n", err)
				os.Exit(3)
			}
			objects = append(objects, data)
		}

		if len(objects) == 0 {
			fmt.Println("json = [];")
			return
		}

		if len(objects) > 1 {
			var stmts []Stmt
			flatten(objects, nil, &stmts)
			for _, s := range stmts {
				p := buildPath(s.Path)
				v := stringifyValue(s.Value)
				fmt.Printf("%s = %s;\n", p, v)
			}
		} else {
			rlines := jsonToGronLines(objects[0])
			for _, line := range rlines {
				fmt.Println(line)
			}
		}
		return
	}

	var data interface{}
	if err := json.Unmarshal(input, &data); err != nil {
		fmt.Fprintf(os.Stderr, "%v\n", err)
		os.Exit(3)
	}

	if jsonStream {
		entries := flattenToStream(data, nil)
		for _, e := range entries {
			pathPart := make([]interface{}, len(e.Path))
			for j, p := range e.Path {
				pathPart[j] = p
			}
			record := []interface{}{pathPart, e.Value}
			out, _ := json.Marshal(record)
			fmt.Println(string(out))
		}
		return
	}

	glines := jsonToGronLines(data)
	for _, line := range glines {
		fmt.Println(line)
	}
}

func printHelp() {
	fmt.Println(`Transform JSON (from a file, URL, or stdin) into discrete assignments to make it greppable

Usage:
  gron [OPTIONS] [FILE|URL|-]

Options:
  -u, --ungron     Reverse the operation (turn assignments back into JSON)
  -v, --values     Print just the values of provided assignments
  -c, --colorize   Colorize output (default on tty)
  -m, --monochrome Monochrome (don't colorize output)
  -s, --stream     Treat each line of input as a separate JSON object
  -k, --insecure   Disable certificate validation
  -x, --proxy      Set proxy configuration
      --noproxy    Comma-separated list of hosts for which not to use a proxy, if one is specified.
  -j, --json       Represent gron data as JSON stream
      --no-sort    Don't sort output (faster)
      --version    Print version information

Exit Codes:
  0	OK
  1	Failed to open file
  2	Failed to read input
  3	Failed to form statements
  4	Failed to fetch URL
  5	Failed to parse statements
  6	Failed to encode JSON

Examples:
  gron /tmp/apiresponse.json
  gron http://jsonplaceholder.typicode.com/users/1 
  curl -s http://jsonplaceholder.typicode.com/users/1 | gron
  gron http://jsonplaceholder.typicode.com/users/1 | grep company | gron --ungron`)
}
GOEOF"}

