		}
		return fmt.Sprintf("%g", val)
	case bool:
		if val {
			return "true"
		}
		return "false"
	case nil:
		return "null"
	case rawMarker:
		return string(val)
	default:
		b, _ := json.Marshal(v)
		return string(b)
	}
}

type rawMarker string

const emptyObj = rawMarker("{}")
const emptyArr = rawMarker("[]")

func makePathSlice(path []interface{}) []interface{} {
	cp := make([]interface{}, len(path))
	copy(cp, path)
	return cp
}

func appendPath(path []interface{}, elem interface{}) []interface{} {
	cp := make([]interface{}, len(path)+1)
	copy(cp, path)
	cp[len(path)] = elem
	return cp
}

func sortKeys(keys []string) {
	sort.Slice(keys, func(i, j int) bool {
		ai, aj := isIdent(keys[i]), isIdent(keys[j])
		if ai && !aj {
			return true
		}
		if !ai && aj {
			return false
		}
		if ai && aj {
			li := strings.ToLower(keys[i])
			lj := strings.ToLower(keys[j])
			if li != lj {
				return li < lj
			}
			return keys[i] < keys[j]
		}
		return keys[i] < keys[j]
	})
}

func flatten(data interface{}, path []interface{}, stmts *[]Stmt) {
	switch val := data.(type) {
	case map[string]interface{}:
		*stmts = append(*stmts, Stmt{Path: makePathSlice(path), Value: emptyObj})
		var keys []string
		for k := range val {
			keys = append(keys, k)
		}
		sortKeys(keys)
		for _, k := range keys {
			newPath := appendPath(path, k)
