func ungronToJSON(stmts []*parsedStmt) (interface{}, error) {
	if len(stmts) == 0 {
		return nil, nil
	}

	rootIsArr := false
	for _, s := range stmts {
		if len(s.Path) == 0 {
			if rm, ok := s.Value.(rawMarker); ok && rm == emptyArr {
				rootIsArr = true
			}
			break
		}
	}

	if rootIsArr {
		return buildFromArrayStmts(stmts)
	}
	return buildFromObjStmts(stmts)
}

func buildFromObjStmts(stmts []*parsedStmt) (interface{}, error) {
	root := make(map[string]interface{})
	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue
		}
		buildInto(root, s.Path, s.Value)
	}
	return root, nil
}

func buildFromArrayStmts(stmts []*parsedStmt) (interface{}, error) {
	maxIdx := -1
	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue
		}
		idx := s.Path[0].(int)
		if idx > maxIdx {
			maxIdx = idx
		}
	}
	result := make([]interface{}, maxIdx+1)

	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue
		}
		idx := s.Path[0].(int)
		if len(s.Path) == 1 {
			result[idx] = s.Value
			continue
		}
		if result[idx] == nil {
			if _, isInt := s.Path[1].(int); isInt {
				result[idx] = make([]interface{}, 0)
			} else {
				result[idx] = make(map[string]interface{})
			}
		}
		buildInto(result[idx], s.Path[1:], s.Value)
	}
	return result, nil
}

func buildInto(container interface{}, path []interface{}, value interface{}) {
	if len(path) == 0 {
		return
	}

	current := container
	for i := 0; i < len(path)-1; i++ {
		key := path[i]
		nextIsInt := (i+1 < len(path))
		if nextIsInt {
			_, nextIsInt = path[i+1].(int)
		}

		switch k := key.(type) {
		case string:
			m := current.(map[string]interface{})
			ensureMapKey(m, k, nextIsInt)
			current = m[k]
		case int:
			a := current.([]interface{})
			a = ensureArrayIdx(a, k, nextIsInt)
			current = a[k]
		}
	}

	// Set final value at leaf
	lastKey := path[len(path)-1]
	switch lk := lastKey.(type) {
	case string:
		m := current.(map[string]interface{})
		if _, exists := m[lk]; !exists {
			m[lk] = value
		} else if !isLeafMarker(value) {
			m[lk] = value
		}
	case int:
		a := current.([]interface{})
		a = ensureArrayIdxForValue(a, lk, value)
		_ = a // current may have changed size, but map already captured
	}
}

func ensureArrayIdxForValue(a []interface{}, idx int, value interface{}) []interface{} {
