	path := []interface{}{}
	rest := pathStr[4:]
	for len(rest) > 0 {
		if rest[0] == '.' {
			rest = rest[1:]
			end := 0
			for end < len(rest) && rest[end] != '[' && rest[end] != '.' {
				end++
