			continue
		}
		idx := s.Path[0].(int)
		if idx > maxIdx {
			maxIdx = idx
		}
	}
	result := make([]interface{}, maxIdx+1)

	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue
		}
		idx := s.Path[0].(int)
		if len(s.Path) == 1 {
			result[idx] = s.Value
			continue
		}
