				case []interface{}:
				case rawMarker:
					// Replace marker with proper container
					if nextIsInt {
						m[k] = RealArray()
					} else {
						m[k] = RealObject()
					}
				default:
					if nextIsInt {
						m[k] = RealArray()
					} else {
						m[k] = RealObject()
					}
				}
			}
			current = m[k]
		case int:
			a := extractArray(current)
			for len(a) <= k {
				a = append(a, nil)
			}
			if a[k] == nil {
				if nextIsInt {
					a[k] = RealArray()
				} else {
					a[k] = RealObject()
				}
			} else {
				switch a[k].(type) {
