{"command": "cat > /work/main.go << 'GOEOF'
package main

import (
	"bufio"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"sort"
	"strings"
)

type Stmt struct {
	Path  []interface{}
	Value interface{}
}

func isIdent(key string) bool {
	if key == "" {
		return false
	}
	for i, r := range key {
		switch {
		case i == 0 && (r >= 'a' && r <= 'z' || r >= 'A' && r <= 'Z'):
			continue
		case i == 0 && r == '_':
			continue
		case i > 0 && (r >= 'a' && r <= 'z' || r >= 'A' && r <= 'Z' || r >= '0' && r <= '9' || r == '_'):
			continue
		default:
			return false
		}
	}
	return true
}

func keyAccess(k interface{}) string {
	switch v := k.(type) {
	case string:
		if isIdent(v) {
			return "." + v
		}
		return fmt.Sprintf(`["%s"]`, v)
	case int:
		return fmt.Sprintf("[%d]", v)
	default:
		return fmt.Sprintf(`[%v]`, v)
	}
}

func buildPath(path []interface{}) string {
	p := "json"
	for _, part := range path {
		p += keyAccess(part)
	}
	return p
}

func stringifyValue(v interface{}) string {
	switch val := v.(type) {
	case string:
		b, _ := json.Marshal(val)
		return string(b)
	case float64:
		if val == float64(int64(val)) {
			return fmt.Sprintf("%d", int64(val))
		}
		return fmt.Sprintf("%g", val)
	case bool:
		if val {
			return "true"
		}
		return "false"
	case nil:
		return "null"
	case containerMarker:
		return string(val)
	default:
		b, _ := json.Marshal(v)
		return string(b)
	}
}

type containerMarker string

const emptyObj = containerMarker("{}")
const emptyArr = containerMarker("[]")

func makePathSlice(path []interface{}) []interface{} {
	cp := make([]interface{}, len(path))
	copy(cp, path)
	return cp
}

func appendPath(path []interface{}, elem interface{}) []interface{} {
	cp := make([]interface{}, len(path)+1)
	copy(cp, path)
	cp[len(path)] = elem
	return cp
}

func sortKeys(keys []string) {
	sort.Slice(keys, func(i, j int) bool {
		ai, aj := isIdent(keys[i]), isIdent(keys[j])
		if ai && !aj {
			return true
		}
		if !ai && aj {
			return false
		}
		if ai && aj {
			li := strings.ToLower(keys[i])
			lj := strings.ToLower(keys[j])
			if li != lj {
				return li < lj
			}
			return keys[i] < keys[j]
		}
		return keys[i] < keys[j]
	})
}

func flatten(data interface{}, path []interface{}, stmts *[]Stmt) {
	switch val := data.(type) {
	case map[string]interface{}:
		*stmts = append(*stmts, Stmt{Path: makePathSlice(path), Value: emptyObj})
		var keys []string
		for k := range val {
			keys = append(keys, k)
		}
		sortKeys(keys)
		for _, k := range keys {
			newPath := appendPath(path, k)
			flatten(val[k], newPath, stmts)
		}
	case []interface{}:
		*stmts = append(*stmts, Stmt{Path: makePathSlice(path), Value: emptyArr})
		for i, item := range val {
			newPath := appendPath(path, i)
			flatten(item, newPath, stmts)
		}
	default:
		*stmts = append(*stmts, Stmt{Path: makePathSlice(path), Value: val})
	}
}

func jsonToGronLines(data interface{}) []string {
	var stmts []Stmt
	flatten(data, nil, &stmts)
	lines := make([]string, len(stmts))
	for i, s := range stmts {
		p := buildPath(s.Path)
		v := stringifyValue(s.Value)
		lines[i] = fmt.Sprintf("%s = %s;", p, v)
	}
	return lines
}

type parsedStmt struct {
	Path  []interface{}
	Value interface{}
}

func unescape(s string) string {
	var result string
	if err := json.Unmarshal([]byte(s), &result); err == nil {
		return result
	}
	return s
}

func parseValue(v string) interface{} {
	v = strings.TrimSpace(v)
	switch v {
	case "null":
		return nil
	case "true":
		return true
	case "false":
		return false
	case "{}":
		return emptyObj
	case "[]":
		return emptyArr
	}
	if len(v) >= 2 && v[0] == '"' && v[len(v)-1] == '"' {
		return unescape(v)
	}
	return v
}

func parsePath(pathStr string) []interface{} {
	if pathStr == "json" {
		return nil
	}
	path := []interface{}{}
	rest := pathStr[4:]
	for len(rest) > 0 {
		if rest[0] == '.' {
			rest = rest[1:]
			end := 0
			for end < len(rest) && rest[end] != '[' && rest[end] != '.' {
				end++
			}
			path = append(path, rest[:end])
			rest = rest[end:]
		} else if rest[0] == '[' {
			rest = rest[1:]
			end := strings.Index(rest, "]")
			if end == -1 {
				break
			}
			slice := rest[:end]
			rest = rest[end+1:]
			if len(slice) >= 2 && slice[0] == '"' && slice[len(slice)-1] == '"' {
				path = append(path, unescape(slice))
			} else {
				var n int
				fmt.Sscanf(slice, "%d", &n)
				path = append(path, n)
			}
		} else {
			break
		}
	}
	return path
}

func parseGrondLine(line string) (*parsedStmt, error) {
	trimmed := strings.TrimSpace(line)
	if trimmed == "" {
		return nil, fmt.Errorf("empty line")
	}
	idx := strings.Index(trimmed, " = ")
	if idx == -1 {
		return nil, fmt.Errorf("invalid format")
	}
	pathStr := trimmed[:idx]
	valStr := trimmed[idx+3:]
	if strings.HasSuffix(valStr, ";") {
		valStr = valStr[:len(valStr)-1]
	}
	path := parsePath(pathStr)
	value := parseValue(valStr)
	return &parsedStmt{Path: path, Value: value}, nil
}

func readStatements(r io.Reader) ([]*parsedStmt, error) {
	var stmts []*parsedStmt
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 1024*1024), 1024*1024)
	for scanner.Scan() {
		line := scanner.Text()
		ps, err := parseGrondLine(line)
		if err != nil {
			continue
		}
		stmts = append(stmts, ps)
	}
	return stmts, nil
}

func isContainerMarker(v interface{}) bool {
	rm, ok := v.(containerMarker)
	return ok && (rm == emptyObj || rm == emptyArr)
}

// node is a reference wrapper that can point either to a map location or an array location
type nodeRef struct {
	container *map[string]interface{}
	key       string
	isArray   bool
	arrParent *map[string]interface{}
	arrKey    string
	idx       int
	bothNil   bool // root-level
}

func (r nodeRef) get() interface{} {
	if r.bothNil {
		return nil
	}
	if r.isArray {
		a := (*r.arrParent)[r.arrKey].([]interface{})
		return a[r.idx]
	}
	m := *r.container
	return m[r.key]
}

func (r nodeRef) set(v interface{}) {
	if r.bothNil {
		return
	}
	if r.isArray {
		(*r.arrParent)[r.arrKey].([]interface{})[r.idx] = v
	} else {
		(*r.container)[r.key] = v
	}
}

func ensureMapVal(m map[string]interface{}, key string, nextIsArray bool) nodeRef {
	val := m[key]
	if val == nil || isContainerMarker(val) {
		// Create new container
		if nextIsArray {
			m[key] = make([]interface{}, 0)
		} else {
			m[key] = make(map[string]interface{})
		}
	} else {
		switch val.(type) {
		case map[string]interface{}:
		case []interface{}:
		default:
			if nextIsArray {
				m[key] = make([]interface{}, 0)
			} else {
				m[key] = make(map[string]interface{})
			}
		}
	}
	return nodeRef{container: &m, key: key}
}

func ensureArrVal(parent map[string]interface{}, parentKey string, idx int, nextIsArray bool) nodeRef {
	a := parent[parentKey].([]interface{})
	orig := a
	for len(a) <= idx {
		a = append(a, nil)
	}
	if a != orig {
		parent[parentKey] = a
	}
	val := a[idx]
	if val == nil || isContainerMarker(val) {
		if nextIsArray {
			a[idx] = make([]interface{}, 0)
		} else {
			a[idx] = make(map[string]interface{})
		}
	} else {
		switch val.(type) {
		case map[string]interface{}:
		case []interface{}:
		default:
			if nextIsArray {
				a[idx] = make([]interface{}, 0)
			} else {
				a[idx] = make(map[string]interface{})
			}
		}
	}
	if a != orig {
		parent[parentKey] = a
	}
	return nodeRef{isArray: true, arrParent: &parent, arrKey: parentKey, idx: idx}
}

func ungronToJSON(stmts []*parsedStmt) (interface{}, error) {
	if len(stmts) == 0 {
		return nil, nil
	}

	rootIsArr := false
	for _, s := range stmts {
		if len(s.Path) == 0 {
			if rm, ok := s.Value.(containerMarker); ok && rm == emptyArr {
				rootIsArr = true
			}
			break
		}
	}

	if rootIsArr {
		return buildFromArrayStmts(stmts)
	}
	return buildFromObjStmts(stmts)
}

func buildFromObjStmts(stmts []*parsedStmt) (interface{}, error) {
	root := make(map[string]interface{})
	rootM := &root
	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue
		}

		// Walk path finding the parent of the leaf
		currentM := rootM
		for i := 0; i < len(s.Path)-1; i++ {
			key := s.Path[i]
			nextIsArr := false
			if i+1 < len(s.Path) {
				_, nextIsArr = s.Path[i+1].(int)
			}

			switch k := key.(type) {
			case string:
				ref := ensureMapVal(*currentM, k, nextIsArr)
				switch ref.get().(type) {
				case map[string]interface{}:
					currentM = ref.container
				case []interface{}:
					// Current key points to array, so we need array handling for next key
					// But wait, if next key is int then we should be navigating into array
					// The ref is the nodeRef for m[k] -- if m[k] is now an array, we need to navigate array
					currentM = &map[string]interface{}{ // this is wrong, need to track array
						k: ref.get(),
					}
				}
				_ = ref
			}
		}
		_ = currentM
	}
	return root, nil
}

// Actually the above approach is getting unwieldy. Let me use a completely different approach:
// Build the object top-down, processing statements by depth.

func buildFromObjStmts_v2(stmts []*parsedStmt) (interface{}, error) {
	root := make(map[string]interface{})

	// Group statements by their path prefix to find container declarations
	// Then process in path order to ensure containers exist before children

	// Actually, let's build iteratively from the outermost keys inward
	// Sort by path length (ascending) and depth-first processing order
	// The key insight: process shorter paths before longer paths at the same level
	// This ensures containers are created before children

	// Filter out root declarations
	contentStmts := make([]*parsedStmt, 0, len(stmts))
	for _, s := range stmts {
		if len(s.Path) > 0 {
			contentStmts = append(contentStmts, s)
		}
	}

	// Group by first key
	type firstLevel struct {
		key     string
		isArr   bool // does the next step go into array?
		stmts   []*parsedStmt
	}
	grouped := make(map[string]*firstLevel)
	for _, s := range contentStmts {
		k := s.Path[0]
		_, isStr := k.(string)
		if !isStr {
			continue // skip non-string root keys (shouldn't happen for object root)
		}
		key := k.(string)
		if _, exists := grouped[key]; !exists {
			_, isArr := s.Path[1].(int)
			grouped[key] = &firstLevel{key: key, isArr: isArr, stmts: nil}
		}
		grouped[key].stmts = append(grouped[key].stmts, s)
	}

	for _, fl := range grouped {
		var child interface{}
		restStmts := make([]*parsedStmt, 0, len(fl.stmts))
		for _, s := range fl.stmts {
			if len(s.Path) == 1 {
				if child == nil || isContainerMarker(child) {
					child = s.Value
				} else if len(s.Path) == 1 {
					// Already set, skip container markers
					if !isContainerMarker(s.Value) && !isContainerMarker(child) {
						// leaf conflict, keep existing
					}
				}
				continue
			}
			restStmts = append(restStmts, s)
		}

		if child == nil || isContainerMarker(child) {
			if fl.isArr {
				result, _ := buildFromArrayStmts(restStmts)
				child = result
			} else {
				result, _ := buildFromObjStmts_v2(restStmts)
				child = result
			}
		}

		root[fl.key] = child
	}

	return root, nil
}

func buildFromArrayStmts_v2(stmts []*parsedStmt) (interface{}, error) {
	maxIdx := -1
	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue
		}
		if len(s.Path) >= 1 {
			if idx, ok := s.Path[0].(int); ok && idx > maxIdx {
				maxIdx = idx
			}
		}
	}
	if maxIdx < 0 {
		return make([]interface{}, 0), nil
	}
	result := make([]interface{}, maxIdx+1)

	// Group by first path element (index)
	type indexed struct {
		idx   int
		stmts []*parsedStmt
	}
	grouped := make([]indexed, maxIdx+1)
	for i := range grouped {
		grouped[i].idx = i
		grouped[i].stmts = nil
	}

	for _, s := range stmts {
		if len(s.Path) == 0 {
			continue
		}
		if idx, ok := s.Path[0].(int); ok {
			grouped[idx].stmts = append(grouped[idx].stmts, s)
		}
	}

	for i, g := range grouped {
		if len(g.stmts) == 0 {
			continue
		}

		leafVal := interface{}(nil)
		restStmts := make([]*parsedStmt, 0)
		for _, s := range g.stmts {
			if len(s.Path) == 1 {
				leafVal = s.Value
				continue
			}
			restStmts = append(restStmts, s)
		}

		if len(restStmts) > 0 {
			_, nextIsArr := restStmts[0].Path[1].(int)
			if nextIsArr {
				// Need to shift paths (remove first element)
				shifted := make([]*parsedStmt, len(restStmts))
				for j, s := range restStmts {
					shifted[j] = &parsedStmt{Path: s.Path[1:], Value: s.Value}
				}
				sub, _ := buildFromArrayStmts_v2(shifted)
				result[i] = sub
			} else {
				shifted := make([]*parsedStmt, len(restStmts))
				for j, s := range restStmts {
					shifted[j] = &parsedStmt{Path: s.Path[1:], Value: s.Value}
				}
				sub, _ := buildFromObjStmts_v2(shifted)
				result[i] = sub
			}
		} else if leafVal != nil {
			result[i] = leafVal
		}
	}
	return result, nil
}

type jsonStreamEntry struct {
	Path  []interface{}
	Value interface{}
}

func flattenToStream(data interface{}, path []interface{}) []jsonStreamEntry {
	var entries []jsonStreamEntry
	switch val := data.(type) {
	case map[string]interface{}:
		entries = append(entries, jsonStreamEntry{Path: makePathSlice(path), Value: map[string]interface{}{}})
		var keys []string
		for k := range val {
			keys = append(keys, k)
		}
		sortKeys(keys)
		for _, k := range keys {
